mapper.select:
SELECT biz_tag, max_id, step, description, update_time, version
FROM leaf_alloc
WHERE biz_tag = #{bizTag}

mapper.update:
UPDATE leaf_alloc
SET max_id = max_id + #{step},
    update_time = CURRENT_TIMESTAMP,
    version = version + 1
WHERE biz_tag = #{bizTag}
  AND version = #{version}
